void SetTextMode(void)

{

   if(textMode)

   {

      playStatus = 1;

      Sound_Holder.SetPlayDSoundParameters(3,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

   else

   {

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(3,0,0,0);

      SetCursor(13-curColor);

   }

}



void MultiBitmap.MouseClickOnDown(int bitmapID,int x,int y,int deep)

{

   if(textMode)   return;

   int oldId=bitmapID;

   bitmapID=((oldId/6)*6)+curColor;

   if(bitmapID!=oldId)

   {

      Sound_Holder.PlayDSound(1);

      MultiBitmap.ShowBitmap(bitmapID,x,y,deep);

      MultiBitmap.HideBitmap(oldId);

   }

}





void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(textMode)   return;

   curColor=rectID;

   SetCursor(13-curColor);

   Sound_Holder.PlayDSound(2);

}





